head.script:
//전역변수-Customer booking 에서 create 로 페이지 링크로 들어 왔을때
scwin.linkType = '';
//전역변수-save인지 update인지 구분해서 cmd호출 0=save, 1=update
scwin.validSaveOrUpdate = 0;
scwin.processFlag = "";  // 처리 결과를 체크하는 Flag
scwin.BilltypeFlag = "";  // Bill Type 을 체크 하는 Flag
scwin.actionFlag = "";
scwin.hd_kcomcd ="DBEX";
scwin.hd_mhno ="";
scwin.hd_iogb ="O";
scwin.hd_temp ="";
/**
 * @ 
 * @name onpageload
 * @description 화면 초기화
 */
scwin.onpageload = function () {
    scwin.globalVars();
    scwin.f_OnLoad();

};
/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {
 //  debugger;
    scwin.paramData = $c.data.getParameter();
//alert("globalVars");
    scwin.cvsslMngtNo = scwin.paramData['cvsslMgntNo'] ?? scwin.paramData['cvsslMgntNo'];
  // 세션정보 가져오기
    const loginDTO = $c.data.getMemInfo();
    scwin.p_lobranCd = loginDTO.lobranCd ?? ''; // 귀속부서코드 
    scwin.p_lobranNm = loginDTO.lobranNm ?? ''; // 귀속부서 명
    scwin.p_userId   = loginDTO.userId   ?? ''; // 사용자 ID

    const resData = $c.gus.dsCommonUtil('getCompanyInfoDTO', scwin.p_lobranCd)[0].value.split('\n');

    const commDTO = resData.reduce((acc, curr) => {
        const match = curr.match(/^\s*\w+\s+(\w+)\s+=\s+\[(.*)\]/);

        if (match) {
            const key = match[1];
            let value = match[2];

            if (value == 'null') value = null;
            acc[key] = value;
        };
        return acc;

    }, {});

    //  default 동부국제물류
    scwin.p_clntNo = commDTO.clntNo ?? '';
    scwin.p_clntNm = commDTO.name1 ?? '';
    scwin.airexgbim = commDTO.airExgbIm ?? '3';

    // 서버날짜 가져오기
    scwin.strCurDate = $c.date.getServerDateTime('yyyyMMdd');

    scwin.kcomCd = scwin.paramData['kcomcd'];
    scwin.mblNo = scwin.paramData['blno'];
    scwin.consolNo = scwin.paramData['mhno'];


    scwin.linkType = scwin.paramData['linkType'];
    scwin.p_ondt   = scwin.paramData['ondt'];    //출발일
    scwin.p_dscd   = scwin.paramData['dscd'];    //출발지코드
    scwin.p_dsnm   = scwin.paramData['dsnm'];    //출발지명
    scwin.p_fltno  = scwin.paramData['fltno'];   //Flight No
    scwin.hd_kcomcd = "DBEX";
    scwin.hd_mhno = "";
    scwin.hd_iogb ="O";
    scwin.hd_temp ="";
    /* 
    scwin.ioGb = paramData['iogb'];
    scwin.p_no = paramData['no'];
    scwin.p_row_cnt = paramData['row_cnt'];
    scwin.p_data = paramData['data'];
    scwin.p_hblno2 = paramData['hblno'];
    scwin.v_linkcheck = paramData['linkcheck'];
*/
    // 메세지 상수 선언
    scwin.MSG_LO_WRN_001 = '@ 에 등록 되어 있어 삭제 불가능 합니다.';
    scwin.MSG_LO_WRN_002 = 'B/L 번호가 Stock 되지 않았습니다.';
    scwin.MSG_LO_WRN_003 = '잘못된 Master Number 입니다.';
    scwin.MSG_LO_WRN_004 = '현재 남은 B/L 수량은  @ 부 입니다.';
    scwin.MSG_LO_WRN_005 = 'Shipment Type 이 Co_Load 일때 Co-Load 정보를 입력 하셔야 합니다.';
    scwin.E_MSG_CM_ERR_039 = '시작일자를 종료일 이전으로 선택[입력]하여 주십시오';
    scwin.E_MSG_CM_WRN_003 = 'Please enter Onboard Date.';
};
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = function () {
//alert("f_OnLoad");
    scwin.f_Set('INIT');
 //   cnd_ed_ondtFrom.focus();
  //  cnd_ed_ondt.focus();
    scwin.f_getParametrSetting(); // link처리
};

//---------------------------------------------------------
// Parameter Setting
//---------------------------------------------------------
scwin.f_getParametrSetting = function(){


    if (scwin.linkType == 'null' || scwin.linkType == ''){
        return false;
    }

    if (scwin.linkType == "MawbookingCreate"){

        scwin.f_Create();

        if (scwin.actionFlag == "Create"){
            ds_MasterBookingList.setCellData(0, 'ondt', scwin.p_ondt);
            ds_MasterBookingList.setCellData(0, 'fltno', scwin.p_fltno);
            ds_MasterBookingList.setCellData(0, 'dscd',scwin.p_dscd);
            ds_MasterBookingList.setCellData(0, 'dsnm',scwin.p_dsnm);
            ds_MasterBookingList.setCellData(0, 'shipgb','C');
            ds_MasterBookingList.setCellData(0, 'bookgb','B');
            ds_MasterBookingList.setCellData(0, 'srgb','N');
            ds_MasterBookingList.setCellData(0, 'lrgb','N');
            ds_MasterBookingList.setRowPosition(0);
            TotalRows.setValue(ds_MasterBookingList.getRowCount());
        }
    }
}; 
//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function() {
    scwin.processFlag = "None";
    scwin.BilltypeFlag = "G";
    lc_shipgb.setValue("C");
    lc_bookgb.setValue("B");
//    lc_srgb.setValue("N");
//    lc_lrgb.setValue("N");
    udc_ondt.focus;
 //   cnd_ed_ondtFrom.focus;
}

/**
 * @method 
 * @name f_Set 
 * @description
 * @param {string} gubun
 */
scwin.f_Set = function (gubun) {
    switch ( gubun ) {
        case "INIT" : //초기화
            ds_MasterBookingSearch.removeAll();
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Create,btn_Mbill]);
            scwin.f_DisablePopUpObj();
            gr_HouseBillList.setReadOnly(false);
    //        alert("chb_voidgb ["+chb_voidgb.getValue()+"]");
    //        chb_voidgb.setValue(null);
            //     gr_HouseBillList.setReadOnly(type, rowIndex, columnInfo, readOnly)  .setDisabled(type, rowIndex, columnInfo, disabled) .Enable = true;
            break;
        case "RETRIEVE" :  //조회모드
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_Mbill]);
            break;
        case "CREATE" : //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);
            scwin.f_DefaultValue();
            gr_HouseBillList.setReadOnly(false);
            break;
        case "UPDATE" :
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Create]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();

            $c.gus.cfDisableObjects([ed_mblno]);
            gr_HouseBillList.setReadOnly(false);
            break;
        case "SAVE" :
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
        case "DELETE" :
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;
    }

};
//-------------------------------------------------------------------------
// PopUp 이미지를 활성화 시킨다.
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function() {
    $c.gus.cfEnableObjects([ed_avdt, ed_ondt, ed_mblno, ed_ontime, ed_avtime, ed_fltno, lc_srgb, lc_lrgb, ed_ctn, ed_gwht,ed_nrate,lc_shipgb, lc_bookgb  ]);
    $c.gus.cfEnableObjects([udc_ca, udc_ed_lecd, udc_ed_cocd, udc_ed_dscd, udc_ed_dpcd, udc_wareCd]);
}
//-------------------------------------------------------------------------
// PopUp 이미지를 비활성화 시킨다.
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function() {
  		$c.gus.cfDisableObjects([ed_avdt, ed_ondt, ed_mblno, ed_ontime, ed_avtime, ed_fltno, lc_srgb, lc_lrgb, ed_ctn, ed_gwht,ed_nrate,lc_shipgb, lc_bookgb ]);
  		$c.gus.cfDisableObjects([udc_ca, udc_ed_lecd, udc_ed_cocd, udc_ed_dscd, udc_ed_dpcd, udc_wareCd]);
};
//-------------------------------------------------------------------------
//조회조건 바인딩
//-------------------------------------------------------------------------
scwin.f_ProcessBinding = function( ds, gubun ) {
    ds.removeAll();
    var row = ds.insertRow();

    if(gubun == "SaveBookingList")
        gr_MasterBookingList.setFocusedCell(0, 0);

    switch ( gubun ) {

        case "RetrieveBooking" :
     //       ds.ClearData();

//            ds.AddRow();
            ds.setCellData(row, "kcomcd", scwin.hd_kcomcd);
            ds.setCellData(row, "ondtFrom", cnd_ed_ondtFrom.getValue() );
            ds.setCellData(row, "ondtTo", cnd_ed_ondtTo.getValue() );
            ds.setCellData(row, "mblno", mblno.getValue().replace('-','') );
            ds.setCellData(row, "dscd", dscd.getValue() );
            break;
        case "RetrieveHouse" :
//            ds.ClearData();
//            ds.AddRow();
//            ds_MasterBookingSearch.setCellData(rowIndex, columnInfo, data)
            ds.setCellData(row, "kcomcd", scwin.hd_kcomcd);
//            ds.setCellData(row, "mblno", mblno.getValue() );
            ds.setCellData(row, "iogb",scwin.hd_iogb);
//            ds.setCellData(row, "mhno",ds_MasterBookingList.getCellData(ds_MasterBookingList.getRowPosition(), "mhno"));

            break;
        case "RetrieveStockNo" :
//            ds.ClearData();
//            ds.AddRow();

            ds.setCellData(row, "kcomcd", scwin.hd_kcomcd);
       //     ds.setCellData(row,  "cacd",  ed_cacd;
            break;
        case "SaveBookingList" :
//            ds.ClearData();
//            ds.AddRow();
            ds.setCellData(row, "kcomcd",scwin.hd_kcomcd);
            break;
        case "RetrieveExistence" :
//            ds.ClearData();
//            ds.AddRow();
//            ds.setCellData(row, "mblno",mblno.getValue().trim());gr_MasterBookingList
              ds.setCellData(gr_MasterBookingList.getFocusedRowIndex(), 'mblno', ds_MasterBookingList.getCellData(gr_MasterBookingList.getFocusedRowIndex(), 'mblno'));
              ds.setCellData(gr_MasterBookingList.getFocusedRowIndex(), 'mhno', ds_MasterBookingList.getCellData(gr_MasterBookingList.getFocusedRowIndex(), 'mhno'));
            //ds_MasterBookingSearch.setCellData(ds_MasterBookingSearch.getRowPosition(), 'mblno', ds_MasterBookingList.getCellData(ds_MasterBookingList.getRowPosition(), 'mblno'));
            //ds_MasterBookingSearch.setCellData(ds_MasterBookingSearch.getRowPosition(), 'mhno', ds_MasterBookingList.getCellData(ds_MasterBookingList.getRowPosition(), 'mhno'));
      //      ds.setCellData(row, "mhno",scwin.hd_mhno);
            break;
        case "RetrieveInsert" :
//            ds.ClearData();
//            ds.AddRow();
            ds.setCellData(row, "kcomcd", scwin.hd_kcomcd);
            ds.setCellData(row,  "mblno", mblno.getValue().trim());
            break;


    }  //end switch
};
//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function( gubun ) {
    actionFlag = "Retrieve";
    switch ( gubun ) {
        case "Search" :
            if ($c.gus.cfIsAfterDate(cnd_ed_ondtFrom.getValue(), cnd_ed_ondtTo.getValue()) == false){
                $c.gus.cfAlertMsg(scwin.E_MSG_CM_ERR_039);  // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
                cnd_ed_ondtFrom.focus();
                return false;
            }
            if (mblno.getValue().length < 11 && cnd_ed_ondtFrom.getValue() == "") {
                $c.gus.cfAlertMsg(scwin.E_MSG_CM_WRN_003,["Onboard Date"]);	//Onboard Date 를 선택해 주세요
                cnd_ed_ondtFrom.focus();
            } else {
                scwin.f_ProcessBinding(ds_MasterBookingSearch, "RetrieveBooking");
                ds_MasterBookingList.removeAll();
                ds_HouseBillList.removeAll();
                $c.sbm.execute(sbm_Retrieve);
   //             tr_Retrieve.Post();
            }
            break;
        case "Insert" :
                scwin.f_ProcessBinding(ds_MasterBookingSearch, "RetrieveInsert");
                ds_MasterBookingList.removeAll();
                ds_HouseBillList.removeAll();
                $c.sbm.execute(sbm_Retrieve);
     //           tr_Retrieve.Post();
            break;
    }
};
//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_ExcelDown = async function () {
    if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
        var options = {
            fileName: "Master Booking List.xlsx",
            sheetName: "Master Booking List",
            startRowIndex: 0,
            startColumnIndex: 0,
            type: 1,
            columnMove: true, //그리드 컬럼이동시 이동된 상태로 다운로드 유무 ( "true"인경우 컬럼이동 순서대로 출력 )
            evenRowBackgroundColor: "#f5fff5"//excel파일에서 그리드 body의 짝수줄의 배경색
        };
        await $c.data.downloadGridViewExcel(gr_MasterBookingList, options);
    } else {
        return;
    }
};
//-------------------------------------------------------------------------
// House b/l 바로 가기 
//-------------------------------------------------------------------------
scwin.f_HouseLink = function(){
    var row = ds_HouseBillList.getRowPosition();

    if(row > 0){

        var v_blno 	= ds_HouseBillList.getCellData(row, "blno");

        var strPath = "/il/airout/aobl/ar_104_01_01b.jsp?kcomcd=" + scwin.hd_kcomcd +
                                                            "&blno="+v_blno;  
        $c.gus.cfTabMenuUpdate( strPath , "Export House B/L");	

    } else {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_056);
        return;
    }
};
//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function(){
    //신규버튼을 누르면 저장,업데이트 구분자를 저장으로 셋팅
    scwin.validSaveOrUpdate = 1;
    ds_HouseBillList.removeAll();
    scwin.f_ProcessBinding( ds_MasterBookingList, "SaveBookingList" );
    scwin.f_Set("CREATE");
    scwin.processFlag = "Create";
    scwin.actionFlag = "Create";
    ed_mblno.focus();
};
//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function(){
    //수정버튼을 누르면 update 구분자를 1로 셋팅
    scwin.actionFlag = "Update";
    scwin.validSaveOrUpdate = 0;
    scwin.f_Set("UPDATE");
};
//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = function(){
   // ds_MasterBookingList.getRowStatus()
//   alert("getRowStatus ["+ds_MasterBookingList.getRowStatus(ds_MasterBookingList.getRowPosition())+"]");s
    if(ds_MasterBookingList.getModifiedIndex().length > 0){
        if (ed_mblno.getValue() == "") {
            if (ed_cacd.getValue() == "") {
                $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Carrier Info"]);
                ed_cacd.focus();
                return false;
            }
            //Master Stock Number Loading 부분
            scwin.f_ProcessBinding(ds_MasterBookingSearch, "RetrieveStockNo");
            //tr_RetrieveMasterStockNo.Post();
            $c.sbm.execute(sbm_RetrieveMasterStockNo); 
            scwin.f_Retrieve("Search"); //재조회
            scwin.BilltypeFlag = "N";
        }
        if (scwin.validSaveOrUpdate == 1) {
            if (scwin.BilltypeFlag == "N") {
                ds_MasterBookingList.setCellData(ds_MasterBookingList.getRowPosition(), "bltype","N");
            } else {
                ds_MasterBookingList.setCellData(ds_MasterBookingList.getRowPosition(), "bltype","G");
            }
        }
        if (scwin.f_ReqFieldChk()) {
            scwin.actionFlag = "Save";
            scwin.processFlag = "Save";
            scwin.f_SaveBinding();
            $c.sbm.execute(sbm_Save);  //저장 실행
       //     tr_Save.Post();

            scwin.f_Set("SAVE");
        }
    }else{
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Master B/L No"]);  /* @은(는) 변경된 사항이 없습니다. */
    }
}  //end if
//-------------------------------------------------------------------------
//저장값  바인딩
//-------------------------------------------------------------------------
scwin.f_SaveBinding = function() {
    ds_MasterBookingList.setCellData(ds_MasterBookingList.getRowPosition(), "mblgb","L");
    if ((ed_lecd.getValue() != "") && (lc_lrgb.getValue() == "R")){
        ds_MasterBookingList.setCellData(ds_MasterBookingList.getRowPosition(), "mblgb", "O");
    }
}
//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function(){
    scwin.validSaveOrUpdate = 0;
    if (scwin.processFlag == "Create") {
        ds_MasterBookingList.removeAll();
        scwin.f_Set("INIT");
        scwin.processFlag = "None";
    } else {
        scwin.f_Set("RETRIEVE");
    }
    ds_MasterBookingList.undoAll();
};
//유효성검사
scwin.f_ReqFieldChk =function() {
    if (ed_mblno.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master B/L No"]);
        ed_mblno.focus();
        return false;
    }
    if (ed_cacd.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Carrier Info"]);
        ed_cacd.focus();
        return false;
    }
    if (ed_ondt.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Onboard Date"]);
        ed_ondt.focus();
        return false;
    }
    if (ed_avdt.getValue() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Arrival Date"]);
        ed_avdt.focus();
        return false;
    }
    //현재선택 되어있는 Combo 의 Code 값을  가져와 체크한다.
    if ((ed_lecd.getValue() != "") && (lc_lrgb.getValue() == "N")) {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master Agent Type"]);
        lc_lrgb.focus();
        return false;
    }
    //현재선택 되어있는 Combo 의 Code 값을  가져와 체크한다.

    if ((ed_cocd.getValue() != "") && (lc_srgb.getValue() == "N")) {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Co_Load Agent Type"]);
        lc_srgb.focus();
        return false;
    }
    if ($c.gus.cfIsAfterDate(ed_ondt.getValue(), ed_avdt.getValue()) == false){
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_039);  // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_ondt.focus();
        return false;
    }
    if (lc_shipgb.getValue() == "L"){
        if (ed_cocd.getValue().trim() == ""){
            $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_005);  // "Shipment Type 이 Co_Load 일때 Co-Load 정보를 입력 하셔야 합니다.";
            ed_cocd.focus();
            return false;
        }
    }
    if ($c.gus.cfValidate([tbl_MasterBookingInfo]) == false){
        return false;
    }

    return true;
};
//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function(){
//debugger;
    scwin.f_ProcessBinding(ds_MasterBookingSearch, "RetrieveExistence");
    //tr_RetrieveMasterExistence.Post();
    $c.sbm.execute(sbm_RetrieveMasterExistence);  //삭제 실행
    if (ds_MasterExistence.getCellData(ds_MasterExistence.getRowPosition(),"blno") != "" ) {
        $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_001,["MAWB"]);  /* @ 에 등록 되어 있어 삭제 불가능 합니다. */
        return false;
    }
    if (ds_MasterExistence.getCellData(ds_MasterExistence.getRowPosition(),"mhno") != "" ) {
        $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_001,["HAWB"]);  /* @ 에 등록 되어 있어 삭제 불가능 합니다. */
        return false;
    }

    if (await $c.win.confirm("Do you wish delete?")) {  //삭제하시겠습니까?
        scwin.actionFlag = "Delete";
        scwin.processFlag = "Delete";
        /*var delarr = ds_MasterBookingList.getDeletedIndex();
         for (var i = ds_MasterBookingList.getRowCount() - 1 ; i >= 0 ; i--){
            for(var j = 0 ; j < delarr.lenth ; j++){
                if (i == j){
                    ds_MasterBookingList.deleteRow(i);
                }
            }
        }*/
        ds_MasterBookingList.deleteRow(gr_MasterBookingList.getFocusedRowIndex());
        $c.sbm.execute(sbm_Save);  //저장 실행
        scwin.f_Set("DELETE");
    }
};
scwin.f_PopUp = function(disGubun, chgGubun) {
    let rtnList = new Array();
    let pCode = '';
    let pName = '';
//debugger;    
    switch (disGubun){

        case "Carrier" :		//거래처 팝업(Search Carrier)
        scwin.hd_temp = "";
        pCode = ed_cacd.getValue().trim();
        pName = txt_canm.getValue();
        udc_ca.setSelectId('retrieveEngCarrInfo');
        rtnList = udc_ca.ilCommonPopUp(scwin.udc_ca_callBackFunc,
                pCode,     // 화면에서의 ??? Code Element의	Value                                  
                pName, 			// 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
