scwin.ed_cocd_onblurCodeEvent = function (e) {
    let strClntNo = ed_cocd.getValue().trim() ;

    if (strClntNo.getlength() > 0) {
        txt_conm.setValue("");
        scwin.f_PopUp("ColoadAgt","T");
    } else {
        txt_conm.setValue("");
        lc_srgb.getSelectedIndex(0);
    }

	if (ed_cocd.getValue().trim() != ""){
		lc_shipgb.getItem("L");
		lc_srgb.setValue(1);
		$c.gus.cfDisableObjects(lc_shipgb);
	} else {
	    lc_shipgb.BindColVal = "C";
		$c.gus.cfEnableObjects(lc_shipgb);
	}    
};

