scwin.lc_shipgb_onchange = function (info) {
	if (lc_shipgb.getValue() == "D"){
		//Co-load 정보 입력 불가 상태로 변경
		ed_cocd.setValue("");
		txt_conm.setValue("");
		lc_srgb.setValue("N");

		$c.gus.cfDisableObjects([udc_ed_cocd, lc_srgb]);
	} else {
		if ((scwin.actionFlag == "Create") || (scwin.actionFlag == "Update")){
			$c.gus.cfEnableObjects([udc_ed_cocd, lc_srgb]);

			if (lc_shipgb.getValue() == "L"){
				//udc_ed_cocd.focus();
			}
		}
	}	
};

scwin.sbm_RetrieveHouseBillList_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {
        $c.gus.cfAlertMsg("House B/L List 조회에러");
    }
    else {
//        houseCnt.setValue(label);
        houseCnt.setValue(ds_HouseBillList.getRowCount());

    }
};

scwin.sbm_RetrieveMasterStockNo_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {
        $c.gus.cfAlertMsg("MasterStockNo 조회에러");
        return;
    }

    if( ds_MasterStockNo.getCellData(0, "mblno") != "" ){
	    scwin.processFlag = "Exist";
	    ed_mblno.setValue(ds_MasterStockNo.getCellData(0, "mblno"));
	} else {
	    scwin.processFlag = "None";
		$c.gus.cfAlertMsg(scwin.MSG_LO_WRN_002);  //B/L 번호가 Stock 되지 않았습니다.
	}
};

